fixed_code:
fn main() {
    #[derive(Debug, PartialEq, Eq)]
    struct Person { name: String, age: u8 }

    let mut people = vec![Person { name: "Alice".into(), age: 30 },
                          Person { name: "Bob".into(), age: 25 }];

    // Use stable sort to ensure relative order of equal elements is preserved
    people.sort_unstable_by_key(|p| p.age);

    println!("{:?}", people);
}

